<script setup lang="ts">
import { reactive, ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useAuthStore } from '../stores/auth'
const mode=ref<'login'|'register'>('login'),loading=ref(false),form=reactive({username:'',email:'',password:''}),auth=useAuthStore(),router=useRouter()
const submit=async()=>{loading.value=true;try{if(mode.value==='login')await auth.login(form.username,form.password);else await auth.register(form.username,form.email,form.password);router.push('/dashboard')}catch(e){ElMessage.error((e as Error).message)}finally{loading.value=false}}
</script>
<template><div class="login-page"><section class="login-story"><div class="story-grid"></div><div class="story-content"><span class="eyebrow light">EARTH OBSERVATION DATA CLOUD</span><h1>让十万级遥感文件<br/>成为可计算的科研资产</h1><p>统一管理 NetCDF、HDF、气象与土地覆盖数据，稳定承载大文件传输，并将AI分析带到数据身边。</p><div class="story-stats"><div><b>170K+</b><span>科研文件</span></div><div><b>10 TB+</b><span>数据规模</span></div><div><b>SHA-256</b><span>可信去重</span></div></div></div></section><section class="login-panel"><div class="login-card"><div class="mobile-brand">CliVegFormer</div><span class="eyebrow">SECURE RESEARCH ACCESS</span><h2>{{mode==='login'?'欢迎回到数据空间':'创建科研账户'}}</h2><p>{{mode==='login'?'登录后继续管理和分析遥感数据。':'注册后即可加入课题组科研数据空间。'}}</p><el-form label-position="top" @submit.prevent="submit"><el-form-item label="用户名"><el-input v-model="form.username" size="large" placeholder="请输入用户名"/></el-form-item><el-form-item v-if="mode==='register'" label="邮箱"><el-input v-model="form.email" size="large" placeholder="name@institute.edu"/></el-form-item><el-form-item label="密码"><el-input v-model="form.password" type="password" show-password size="large" placeholder="至少 8 位" @keyup.enter="submit"/></el-form-item><el-button type="primary" size="large" :loading="loading" @click="submit">{{mode==='login'?'登录平台':'注册并登录'}}</el-button></el-form><button class="mode-link" @click="mode=mode==='login'?'register':'login'">{{mode==='login'?'还没有账户？立即注册':'已有账户？返回登录'}}</button></div></section></div></template>
